    let sum = 0;
    for (let num of nums) {
        let divCount = 0;
        let divSum = 0;

        for (let i = 1; i * i <= num; ++i) {
            if (num % i === 0) {
                divSum += i;
                ++divCount;

                if (num / i !== i) {
                    divSum += (num / i);
                    ++divCount;
